public void init()
{
    ETGCanadaParameters etgParams;
    FormControl descCtrl;
    boolean enableDesc;

    next init();

    // Fetch parameter record
    etgParams = ETGCanadaParameters::find();
    enableDesc = (etgParams.EnableProductionDescription == NoYes::Yes);

    descCtrl = this.design().controlName(identifierStr(ProdTable_ETGDescription));



    if (descCtrl)
    {
        // Control visibility based on parameter setup
        descCtrl.visible(enableDesc);

        // Control editability based on parameter setup
        descCtrl.enabled(enableDesc);
    }
}
